class Solution {
    public String robotWithString(String s) {
        int n = s.length();
        char[] res = new char[n];
        int p = 0, t = 0;
        int[] count = new int[26];
        for (int i = n - 1; i >= 0; i--) {
            count[s.charAt(i) - 'a']++;
        }
        for (int i = 0; i < n; i++) {
            while (t < n && (p == n || s.charAt(p) - 'a' >= s.charAt(t) - 'a')) {
                res[i] = s.charAt(t);
                t++;
                i--;
            }
            count[s.charAt(p) - 'a']--;
            p++;
        }
        return new String(res);
    }
}
```

